     1→import { NextRequest, NextResponse } from 'next/server'
     2→import { prisma } from '@/lib/prisma'
     3→
     4→export async function GET(
     5→    req: NextRequest,
     6→    { params }: { params: Promise<{ id: string }> }
     7→) {
     8→    try {
     9→        const { id } = await params
    10→
    11→        const dossier = await prisma.dossier.findUnique({
    12→            where: { id },
    13→            include: {
    14→                cards: true,
    15→            },
    16→        })
    17→
    18→        if (!dossier) {
    19→            return new Response('Dossier not found', { status: 404 })
    20→        }
    21→
    22→        return NextResponse.json(dossier)
    23→    } catch (error) {
    24→        console.error('Fetch dossier error:', error)
